    ticker = item['ticker']
    days = int(item['high_vol_days'])
    if ticker not in cleaned_results or days > int(cleaned_results[ticker]['high_vol_days']):
        cleaned_results[ticker] = {'ticker': ticker, 'high_vol_days': str(days)}

